// ========================================
// WF1 v5 - SPLIT RESULTS TO ITEMS
// Chuyển array results thành từng items riêng
// ========================================

const response = $input.first().json;
const results = response.results || [];

if (results.length === 0) {
  console.log('Không có Clarification nào cần gửi email');
  return [];
}

console.log(`Tìm thấy ${results.length} Clarification cần xử lý`);

// Return từng item để n8n loop qua
return results.map(item => ({ json: item }));

// ========================================
// WF1 v5 - EXTRACT CLARIFICATION DATA
// Xử lý từng Clarification item
// ========================================

const item = $input.first().json;
const properties = item.properties || {};

// ========== HELPER: Get field by type and keywords ==========
function getField(type, keywords) {
  for (const [name, data] of Object.entries(properties)) {
    if (data.type !== type) continue;
    const nameLower = name.toLowerCase();
    if (keywords.some(kw => nameLower.includes(kw.toLowerCase()))) {
      if (type === 'title') return data.title?.[0]?.plain_text || '';
      if (type === 'rich_text') return data.rich_text?.[0]?.plain_text || '';
      if (type === 'select') return data.select?.name || '';
      if (type === 'date') return data.date?.start || '';
      if (type === 'email') return data.email || '';
      if (type === 'number') return data.number || 0;
    }
  }
  return '';
}

// ========== EXTRACT TITLE ==========
let tieuDe = '';
for (const [name, data] of Object.entries(properties)) {
  if (data.type === 'title' && data.title?.[0]) {
    tieuDe = data.title[0].plain_text || '';
    break;
  }
}

// ========== EXTRACT OTHER FIELDS ==========
const tinhTrang = getField('select', ['tình trạng', 'status']);
const noiDungGoc = getField('rich_text', ['nội dung', 'gốc']);
const t2NhiemVu = getField('rich_text', ['nhiệm vụ', 't2']);
const t3ChiTieu = getField('rich_text', ['chỉ tiêu', 't3']);
const t4ThoiHan = getField('date', ['thời hạn', 't4', 'deadline']);
const nguonGiaoViec = getField('select', ['nguồn']);
const uuTien = getField('select', ['ưu tiên', 'priority']);
const emailDauMoi = getField('email', ['email', 'đầu mối']);

// ========== GET HR RELATION ==========
let hrRelationId = '';
for (const [name, data] of Object.entries(properties)) {
  if (data.type === 'relation') {
    const nameLower = name.toLowerCase();
    if (nameLower.includes('người nhận') || nameLower.includes('hr') || nameLower.includes('chỉ đạo')) {
      if (data.relation && data.relation.length > 0) {
        hrRelationId = data.relation[0].id || '';
      }
      break;
    }
  }
}

// ========== EMAIL SOURCE LOGIC ==========
let emailSource = 'fallback';
let primaryEmail = '';

if (emailDauMoi && emailDauMoi.includes('@')) {
  emailSource = 'direct_field';
  primaryEmail = emailDauMoi;
} else if (hrRelationId) {
  emailSource = 'hr_lookup';
  primaryEmail = '';
} else {
  emailSource = 'fallback';
  primaryEmail = 'vynnl@esuhai.com';
}

// ========== BUILD OUTPUT ==========
const output = {
  clarificationId: item.id,
  clarificationUrl: item.url || `https://www.notion.so/${item.id.replace(/-/g, '')}`,

  tieuDe: tieuDe,
  tinhTrang: tinhTrang,
  noiDungGoc: noiDungGoc,
  t2NhiemVu: t2NhiemVu,
  t3ChiTieu: t3ChiTieu,
  t4ThoiHan: t4ThoiHan,
  nguonGiaoViec: nguonGiaoViec || 'CEO',
  uuTien: uuTien,

  emailSource: emailSource,
  primaryEmail: primaryEmail,
  hrRelationId: hrRelationId,
  fallbackPrimary: 'vynnl@esuhai.com',
  fallbackCC: 'hoangkha@esuhai.com',

  has4T: Boolean(tieuDe && t2NhiemVu && t3ChiTieu && t4ThoiHan)
};

console.log('Processing:', tieuDe.substring(0, 40));
console.log('Email Source:', emailSource);

return output;

// ========================================
// WF1 v5 - BUILD EMAIL (DIRECT)
// Email từ field "📧 Email đầu mối"
// ========================================

const data = $input.first().json;

const formId = '1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

const params = [
  `entry.123456789=${encodeURIComponent(data.clarificationId)}`,
  `entry.987654321=${encodeURIComponent(data.tieuDe || '')}`,
  `entry.111111111=${encodeURIComponent(data.t2NhiemVu || '')}`,
  `entry.222222222=${encodeURIComponent(data.t3ChiTieu || '')}`,
  `entry.333333333=${encodeURIComponent(data.t4ThoiHan || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

console.log('BUILD DIRECT - To:', data.primaryEmail);

return {
  ...data,
  sendTo: data.primaryEmail,
  ccEmail: '',
  bccEmail: 'hoangkha@esuhai.com',
  prefillUrl: prefillUrl,
  emailResolution: 'direct_field'
};

// ========================================
// WF1 v5 - BUILD EMAIL (HR LOOKUP)
// Lấy email từ HR page, fallback nếu không có
// ========================================

const hrPage = $input.first().json;
const originalData = $('Extract Clarification Data').first().json;

let hrEmail = '';
const props = hrPage.properties || {};

for (const [name, data] of Object.entries(props)) {
  if (data.type === 'email' && data.email) {
    hrEmail = data.email;
    break;
  }
  if (data.type === 'rich_text' && data.rich_text?.[0]?.plain_text) {
    const text = data.rich_text[0].plain_text;
    if (text.includes('@')) {
      hrEmail = text.trim();
      break;
    }
  }
}

let sendTo = hrEmail;
let ccEmail = '';
let emailResolution = 'hr_lookup';

if (!hrEmail) {
  sendTo = originalData.fallbackPrimary;
  ccEmail = originalData.fallbackCC;
  emailResolution = 'fallback_from_hr';
}

const formId = '1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

const params = [
  `entry.123456789=${encodeURIComponent(originalData.clarificationId)}`,
  `entry.987654321=${encodeURIComponent(originalData.tieuDe || '')}`,
  `entry.111111111=${encodeURIComponent(originalData.t2NhiemVu || '')}`,
  `entry.222222222=${encodeURIComponent(originalData.t3ChiTieu || '')}`,
  `entry.333333333=${encodeURIComponent(originalData.t4ThoiHan || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

console.log('BUILD HR - To:', sendTo, '| Resolution:', emailResolution);

return {
  ...originalData,
  sendTo: sendTo,
  ccEmail: ccEmail,
  bccEmail: 'hoangkha@esuhai.com',
  prefillUrl: prefillUrl,
  emailResolution: emailResolution,
  hrEmailFound: hrEmail
};

// ========================================
// WF1 v5 - BUILD EMAIL (FALLBACK)
// Không có email đầu mối, không có HR relation
// ========================================

const data = $input.first().json;

const formId = '1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

const params = [
  `entry.123456789=${encodeURIComponent(data.clarificationId)}`,
  `entry.987654321=${encodeURIComponent(data.tieuDe || '')}`,
  `entry.111111111=${encodeURIComponent(data.t2NhiemVu || '')}`,
  `entry.222222222=${encodeURIComponent(data.t3ChiTieu || '')}`,
  `entry.333333333=${encodeURIComponent(data.t4ThoiHan || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

console.log('BUILD FALLBACK - To:', data.fallbackPrimary);

return {
  ...data,
  sendTo: data.fallbackPrimary,
  ccEmail: data.fallbackCC,
  bccEmail: 'hoangkha@esuhai.com',
  prefillUrl: prefillUrl,
  emailResolution: 'fallback_direct'
};
